module nvme_controller(  
    input clk,  
    input reset,  
    input command,  
    output reg done  
);  
    reg [1:0] state;  
    reg [3:0] obf_count;  
    parameter IDLE = 2'b00, PROCESSING = 2'b01, DONE = 2'b10;  
    parameter N = 4'b0011;  // Processing duration (3 clock cycles)  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            state <= IDLE;  
            done <= 0;  
            obf_count <= 0;  
        end else begin  
            case(state)  
                IDLE: begin  
                    done <= 0;  
                    if (command)  
                        state <= PROCESSING;  
                end  
                PROCESSING: begin  
                    obf_count <= obf_count + 1;  
                    if (obf_count == N) begin  
                        state <= DONE;  
                        obf_count <= 0;  
                    end  
                end  
                DONE: begin  
                    done <= 1;  
                    state <= IDLE;  
                end  
            endcase  
        end  
    end  
endmodule
